import re
import pandas as pd

def valores_a7bd(data):
    skip = {"code"}
    ind_cols = [col for col in data.columns if col not in skip]
    pattern = r'^.+\.raw\.\d{4}$'
    rows = []
    for iso, row in data.iterrows():
        for col in ind_cols:
            match = re.match(pattern, col)
            if match:
                indicator_code = col.split('.')[0]
                year = int(col.split('.')[-1])
                rows.append({"location_code": row['iso'], "indicator_code": indicator_code, "indicator_name": indicator_code, "year": year, "value": row[col]})
    return pd.DataFrame(rows).dropna(subset=["location_code","indicator_code","year","value"])

