def valores_4c72(data):
    skip = {"Unnamed: 0", "Unnamed: 1", "Unnamed: 2", "Unnamed: 3"}
    ind_cols = [c for c in data.columns if c not in skip]
    rows = []
    for _, r in data.iterrows():
        if not pd.isna(r["HUMAN FREEDOM"]):
            loc = r["Unnamed: 3"]
            ind_code = "Ai Procedural Justice" if len(ind_cols) > 1 else r["HUMAN FREEDOM"]
            ind_name = ind_code
            year = int(r["Unnamed: 0"])
            value = float(r["HUMAN FREEDOM"])
            for col in ind_cols[1:]:
                if not pd.isna(r[col]):
                    if col != "HUMAN FREEDOM":
                        ind_name = col
                    value = float(r[col])
                    break
            rows.append({"location_code": loc, "indicator_code": ind_code, "indicator_name": ind_name, "year": year, "value": value})
    return pd.DataFrame(rows).dropna(subset=["location_code","indicator_code","year","value"])
